gBAAA;Edw7CF;Ecr7CA;IACE,eAAA;Edu7CF;Ecp7CA;IACE,eAAA;Eds7CF;Ecn7CA;IACE,eAAA;IACA,mBAAA;Edq7CF;Ecl7CA;;mBAAA;EAGA;IACE,kBAAA;Edo7CF;Ecj7CA;;qBAAA;EAGA;IACE,mBAAA;Edm7CF;Ech7CA;IACE,mBAAA;Edk7CF;Ec96CA;IACE,YAAA;Edg7CF;AACF;Ac76CA,0DAAA;AACA;EAEE;;qBAAA;EAGA;IACE,gBAAA;IACA,kBAAA;Ed86CF;Ec36CA;IACE,YAAA;IACA,gBAAA;IACA,WAAA;Ed66CF;Ec16CA;IACE,mBAAA;IACA,kBAAA;Ed46CF;Ecz6CA;IACE,mBAAA;Ed26CF;Ecx6CA;;4BAAA;EAGA;;IAEE,WAAA;Ed06CF;Ecv6CA;IACE,eAAA;IACA,iBAAA;Edy6CF;Ecr6CA;IACE,eAAA;IACA,iBAAA;Edu6CF;Ecn6CA;IACE,eAAA;IACA,iBAAA;Edq6CF;Ecl6CA;;sBAAA;EAGA;IACE,iBAAA;Edo6CF;Ecj6CA;IACE,eAAA;Edm6CF;Ech6CA;;qBAAA;EAGA;IACE,oBAAA;Edk6CF;Ec/5CA;;qBAAA;EAGA;IACE,WAAA;IACA,WAAA;IACA,mBAAA;Edi6CF;Ec95CA;IACE,UAAA;IACA,YAAA;IACA,iBAAA;Edg6CF;Ec75CA;IACE,gBAAA;Ed+5CF;Ec55CA;IACE,oBAAA;Ed85CF;Ec15CA;IACE,YAAA;Ed45CF;Ecz5CA;IACE,mBAAA;Ed25CF;Ecx5CA;;wBAAA;EAGA;IACE,aAAA;Ed05CF;Ecv5CA;;qBAAA;EAIA;IACE,mBAAA;IACA,kBAAA;Edw5CF;Ecr5CA;;qBAAA;EAGA;IACE,mBAAA;Edu5CF;Ecp5CA;IACE,aAAA;IACA,gBAAA;IACA,kBAAA;Eds5CF;Ecn5CA;IACE,eAAA;Edq5CF;Ecl5CA;IACE,eAAA;Edo5CF;Ecj5CA;;mBAAA;EAGA;IACE,kBAAA;Edm5CF;Ech5CA;;qBAAA;EAGA;IACE,mBAAA;Edk5CF;Ec/4CA;IACE,mBAAA;Edi5CF;AACF","file":"style.css","sourcesContent":["/*=== MEDIA QUERY ===*/\n@mixin mobile-xs{\n  @media(max-width:400px){\n    @content;\n  }\n}\n@mixin mobile{\n  @media(max-width:480px){\n    @content;\n  }\n}\n@mixin tablet{\n  @media(max-width:768px){\n    @content;\n  }\n}\n@mixin desktop{\n  @media(max-width:992px){\n    @content;\n  }\n}\n@mixin large-desktop{\n  @media(max-width:1200px){\n    @content;\n  }\n}","/*\n* ----------------------------------------------------------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.PRELOADER & BOUNCE CCS STYLE\n* 03.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n* 04.ABOUT CSS STYLE\n* 05.SERVICE CSS STYLE\n* 06.WORK CSS STYLE\n* 07.AVAILABLE CSS STYLE\n* 08.CONTACT CSS STYLE\n* 09.FOOTER CSS STYLE\n* ----------------------------------------------------------------------------------------\n*/\n\n/*\n* ----------------------------------------------------------------------------------------\n* 01.GLOBAL STYLE\n* ----------------------------------------------------------------------------------------\n*/\n// Fonts \n@import url('https://fonts.googleapis.com/css?family=Poppins:400,600,700|Rubik:400,600,700');\n\n\nbody {\n  font-size: 16px;\n  font-weight: 400;\n  line-height: 26px;\n  font-family: $secondary-font;\n  color: #788487;\n  position: relative;\n}\n\np {\n  line-height: 28px;\n  font-size: 15px;\n}\n\nhtml {\n  overflow-x: hidden !important;\n  width: 100%;\n  height: 100%;\n  position: relative;\n  -webkit-font-smoothing: antialiased;\n  text-rendering: optimizeLegibility;\n}\n\nbody {\n  border: 0;\n  margin: 0;\n  padding: 0;\n}\n\nh1,\n.h1,\nh2,\n.h2,\nh3,\n.h3,\nh4,\n.h4,\nh5,\n.h5,\nh6,\n.h6 {\n  font-family: $primary-font;\n  font-weight: 600;\n  margin-bottom: 0px;\n  color: $black-light;\n}\n\na {\n  text-decoration: none;\n  -webkit-transition: all 0.4s;\n  -webkit-transition: all 0.2s;\n  transition: all 0.2s;\n  color: $black;\n}\n\nimg {\n  max-width: 100%;\n}\n\na:hover {\n  color: #635CDB;\n  text-decoration: none;\n}\n\na:focus {\n  outline: none;\n  text-decoration: none;\n}\n\nul,\nli {\n  margin: 0;\n  padding: 0;\n  list-style: none;\n}\n\n\n\n\nh1 {\n  font-size: 48px;\n}\n\nh2 {\n  font-size: 36px;\n}\n\nh3 {\n  font-size: 28px;\n  line-height: 38px;\n}\n\nh4 {\n  font-size: 22px;\n  line-height: 32px;\n}\n\nh5 {\n  font-size: 16px;\n  line-height: 24px;\n}\n\nh6 {\n  font-size: 14px;\n  line-height: 26px;\n}\n\n\n.f-color {\n  color: #635CDB;\n}\n\nh5.subtitle {\n  font-size: 16px;\n  font-weight: 400;\n}","$light: #fff;\n$primary-color: #00a7e1;\n$secondary-color: #f4f4f4;\n$black: #0b80bb;\n$black-light: #232323;\n$black-lighter: #888;\n$border-color:#eee;\n$primary-font:'Poppins', sans-serif;\n$secondary-font:'Rubik', sans-serif;\n","/*=== MEDIA QUERY ===*/\n/*\n* ----------------------------------------------------------------------------------------\n* 01.GLOBAL CSS STYLE\n* 02.PRELOADER & BOUNCE CCS STYLE\n* 03.HOMEPAGE CSS STYLE\n    -LOGO CSS\n    -MENU CSS\n* 04.ABOUT CSS STYLE\n* 05.SERVICE CSS STYLE\n* 06.WORK CSS STYLE\n* 07.AVAILABLE CSS STYLE\n* 08.CONTACT CSS STYLE\n* 09.FOOTER CSS STYLE\n* ----------------------------------------------------------------------------------------\n*/\n/*\n* ----------------------------------------------------------------------------------------\n* 01.GLOBAL STYLE\n* ----------------------------------------------------------------------------------------\n*/\n@import url(\"https://fonts.googleapis.com/css?family=Poppins:400,600,700|Rubik:400,600,700\");\nbody {\n  font-size: 16px;\n  font-weight: 400;\n  line-height: 26px;\n  font-family: \"Rubik\", sans-serif;\n  color: #788487;\n  position: relative;\n}\n\np {\n  line-height: 28px;\n  font-size: 15px;\n}\n\nhtml {\n  overflow-x: hidden !important;\n  width: 100%;\n  height: 100%;\n  position: relative;\n  -webkit-font-smoothing: antialiased;\n  text-rendering: optimizeLegibility;\n}\n\nbody {\n  border: 0;\n  margin: 0;\n  padding: 0;\n}\n\nh1,\n.h1,\nh2,\n.h2,\nh3,\n.h3,\nh4,\n.h4,\nh5,\n.h5,\nh6,\n.h6 {\n  font-family: \"Poppins\", sans-serif;\n  font-weight: 600;\n  margin-bottom: 0px;\n  color: #232323;\n}\n\na {\n  text-decoration: none;\n  -webkit-transition: all 0.4s;\n  -webkit-transition: all 0.2s;\n  transition: all 0.2s;\n  color: #0b80bb;\n}\n\nimg {\n  max-width: 100%;\n}\n\na:hover {\n  color: #635CDB;\n  text-decoration: none;\n}\n\na:focus {\n  outline: none;\n  text-decoration: none;\n}\n\nul,\nli {\n  margin: 0;\n  padding: 0;\n  list-style: none;\n}\n\nh1 {\n  font-size: 48px;\n}\n\nh2 {\n  font-size: 36px;\n}\n\nh3 {\n  font-size: 28px;\n  line-height: 38px;\n}\n\nh4 {\n  font-size: 22px;\n  line-height: 32px;\n}\n\nh5 {\n  font-size: 16px;\n  line-height: 24px;\n}\n\nh6 {\n  font-size: 14px;\n  line-height: 26px;\n}\n\n.f-color {\n  color: #635CDB;\n}\n\nh5.subtitle {\n  font-size: 16px;\n  font-weight: 400;\n}\n\n.no-padding {\n  padding: 0;\n}\n\n.flaticon {\n  display: inline;\n}\n\n.mb30 {\n  margin-bottom: 30px;\n}\n\n.section-padding {\n  padding: 90px 0px;\n}\n\n.section-heading {\n  text-align: center;\n  width: 70%;\n  margin: 0 auto 60px;\n}\n\n.section-title {\n  font-size: 32px;\n  line-height: 38px;\n  margin-bottom: 15px;\n  text-transform: capitalize;\n}\n\n.section-title span {\n  color: #00a7e1;\n}\n\n.section {\n  padding: 100px 0px;\n}\n\n.line {\n  width: 50px;\n  background: #00a7e1;\n  height: 1px;\n  margin: 10px auto;\n}\n\n/*---------- BUTTONS ----------*/\n.btn {\n  font: 600 10.5px/1;\n  display: inline-block;\n  padding: 15px 45px 15px 45px;\n  text-transform: uppercase;\n  border: 2px solid transparent;\n  -webkit-transition: all 0.2s;\n  transition: all 0.2s;\n  border-radius: 0px;\n  font-weight: 600;\n  font-size: 13px;\n  letter-spacing: 1px;\n}\n\n.btn:focus,\n.btn:active,\n.btn:active:focus {\n  outline: none;\n  box-shadow: none;\n}\n\n.btn-hero,\n.btn-white:hover {\n  color: #fff !important;\n  background: #00a7e1;\n}\n\n.btn-hero:focus {\n  color: #fff !important;\n}\n\n.btn-black,\n.btn-hero:hover {\n  background-color: rgb(0, 0, 0);\n  color: #fff !important;\n}\n\n.btn-black:hover {\n  color: #fff;\n  background: #00a7e1;\n}\n\n.btn-black:focus {\n  color: #fff;\n}\n\n.btn-white {\n  background-color: rgba(255, 255, 255, 0.95);\n  color: rgba(0, 0, 0, 0.85);\n  border-color: rgba(255, 255, 255, 0.12);\n}\n\n.btn-white:focus {\n  color: #0b80bb;\n}\n\n.btn-white:active {\n  color: #fff;\n}\n\n.btn-trans-black {\n  background-color: transparent;\n  border: 2px solid rgba(0, 0, 0, 0.15);\n  color: rgba(0, 0, 0, 0.85);\n}\n\n.btn-trans-black:hover {\n  color: rgb(255, 255, 255);\n  background-color: #0b80bb;\n}\n\n.btn-trans-white {\n  background-color: transparent;\n  border: 2px solid rgba(255, 255, 255, 0.15);\n  color: rgba(255, 255, 255, 0.95);\n}\n\n.btn-trans-white:hover {\n  background-color: rgba(255, 255, 255, 0.95);\n  color: rgba(0, 0, 0, 0.85);\n  border-color: rgba(255, 255, 255, 0.12);\n}\n\n.btn-trans-white:active,\n.btn-trans-white:focus {\n  color: #fff;\n  background-color: transparent;\n  border-color: rgba(255, 255, 255, 0.12);\n}\n\n.btn-rounded {\n  border-radius: 2px;\n}\n\n.btn-circled {\n  border-radius: 40px;\n}\n\n.btn-trans-black:hover {\n  background: #00a7e1 !important;\n}\n\n/*---------- COLORS ----------*/\n/*-- Background Colors --*/\n.bg-black {\n  background-color: #0b80bb;\n}\n\n.bg-dark {\n  background-color: rgba(0, 0, 0, 0.96);\n}\n\n.bg-feature {\n  background-color: #00a7e1;\n}\n\n.bg-primary {\n  background-color: #0db8ca;\n}\n\n.bg-gray {\n  background-color: #f2f4ec;\n}\n\n.bg-white {\n  background-color: #fff;\n}\n\n.d-table {\n  width: 100%;\n}\n\n.d-table-cell {\n  vertical-align: middle;\n}\n\n.overlay {\n  position: absolute;\n  top: 0px;\n  left: 0px;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.5);\n}\n\n.brown-overlay {\n  background: #222955;\n  opacity: 0.97;\n}\n\n.feature-overlay {\n  background: #00a7e1;\n  opacity: 0.97;\n}\n\n.gr-overlay {\n  background: linear-gradient(135deg, #2f1ce0 0%, #53a0fd 30%, #51eca5 100%);\n  opacity: 0.87;\n}\n\n/* ========================\n\n==============================*/\n.heading {\n  margin-bottom: 40px;\n}\n\n.heading h3 {\n  margin-bottom: 10px;\n  font-weight: 600;\n}\n\n/*------------------------------------\n  MENU NAVIGATION AREA\n----------------------------------*/\n.site-navigation,\n.trans-navigation {\n  padding: 20px 0px;\n}\n\n.site-navigation .navbar-nav a,\n.trans-navigation .navbar-nav a {\n  text-transform: uppercase;\n}\n\n.site-navigation .navbar-nav a.active,\n.trans-navigation .navbar-nav a.active {\n  color: red;\n}\n\n.header-white {\n  position: fixed;\n  top: 0px;\n  background: #111;\n  z-index: 9999;\n  width: 100%;\n  left: 0;\n  -webkit-transition: all 0.3s ease 0s;\n  -o-transition: all 0.5s ease 0s;\n  transition: all 0.5s ease 0s;\n  color: #0b80bb !important;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link,\n.navbar-expand-lg.site-navigation .navbar-nav .nav-link {\n  padding: 0px 24px;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link:last-child,\n.navbar-expand-lg.site-navigation .navbar-nav .nav-link:last-child {\n  padding-right: 0px;\n}\n\n.site-navigation,\n.trans-navigation {\n  -webkit-transition: all 0.3s ease 0s;\n  -o-transition: all 0.5s ease 0s;\n  transition: all 0.5s ease 0s;\n}\n\n.navbar-brand {\n  padding-top: 0px;\n  margin-right: 60px;\n  font-weight: 700;\n  text-transform: capitalize;\n  color: #fff;\n}\n\n.navbar-brand span {\n  font-weight: 400;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link {\n  color: #fff;\n}\n\n.trans-navigation {\n  background: transparent;\n}\n\n.trans-navigation.header-white {\n  background: #111;\n}\n\n.trans-navigation.header-white .navbar-nav .nav-link {\n  color: #fff;\n}\n\n.trans-navigation.header-white .navbar-nav a.active {\n  color: #00a7e1;\n}\n\n.navbar-brand img {\n  max-width: 100%;\n}\n\n.trans-navigation.header-white .btn-white {\n  background: #00a7e1;\n  color: #fff;\n}\n\n/* ===============================\n DROPDOWN MENU\n================================*/\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link.dropdown-toggle {\n  padding-right: 0px;\n}\n\n.dropdown-toggle i {\n  font-size: 10px;\n  vertical-align: 2px;\n}\n\n.dropdown-menu {\n  padding: 0px;\n  border: 0;\n  box-shadow: 2px 2px 5px 1px rgba(0, 0, 0, 0.05), -2px 0px 5px 1px rgba(0, 0, 0, 0.05);\n}\n@media (max-width: 992px) {\n  .dropdown-menu {\n    text-align: center;\n    float: left !important;\n    width: 100%;\n    margin: 0;\n  }\n}\n.dropdown-menu li:first-child {\n  margin-top: 5px;\n}\n.dropdown-menu li:last-child {\n  margin-bottom: 5px;\n}\n\n.dropdown-toggle::after {\n  display: none;\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: \"Font Awesome 5 Free\";\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 5px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 5px;\n}\n\n.dropdown-item {\n  padding: 0.6rem 1.5rem 0.35rem;\n  text-transform: uppercase;\n  font-size: 14px;\n  font-weight: 500;\n}\n\n.dropdown-submenu.active > .dropdown-toggle,\n.dropdown-submenu:hover > .dropdown-item,\n.dropdown-item.active,\n.dropdown-item:hover {\n  background: rgba(0, 167, 225, 0.1);\n  color: #00a7e1;\n}\n\nbutton:focus {\n  outline: 0;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width: 992px) {\n  .dropdown-menu {\n    transition: all 0.2s ease-in, visibility 0s linear 0.2s, transform 0.2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(10px);\n  }\n  .dropdown-menu li:first-child {\n    margin-top: 5px;\n  }\n  .dropdown-menu li:last-child {\n    margin-bottom: 5px;\n  }\n  .dropleft .dropdown-menu,\n  .dropright .dropdown-menu {\n    margin-top: -5px;\n  }\n  .dropdown:hover > .dropdown-menu {\n    visibility: visible;\n    transition: all 0.3s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n@media (max-width: 992px) {\n  .navbar-collapse {\n    text-align: center;\n  }\n}\n.navbar-collapse.show {\n  overflow-y: auto;\n  max-height: calc(100vh - 100px);\n}\n\n/*------------------------------------\n BANNER AREA\n----------------------------------*/\n.banner-area .content-padding {\n  padding: 250px 0px 180px;\n}\n\n.content-padding {\n  padding: 180px 0px 80px;\n}\n\n.banner-content {\n  padding-right: 30px;\n}\n\n.banner-content .btn {\n  margin-top: 15px;\n}\n\n.banner-content .banner-title {\n  color: #fff;\n  font-weight: 700;\n  line-height: 50px;\n}\n\n.banner-content .subtitle {\n  color: #fff;\n  background: #00a7e1;\n  display: inline-block;\n  padding: 3px 8px;\n  margin-bottom: 20px;\n  text-transform: uppercase;\n}\n\n.subtitle {\n  color: #00a7e1;\n}\n\n.banner-content p {\n  margin: 20px 0px;\n  color: #eee;\n  font-size: 18px;\n  line-height: 30px;\n}\n\n.banner-content .btn {\n  margin-right: 12px;\n}\n\n.btn-sm {\n  padding: 10px 30px;\n}\n\n.banner-1 {\n  background: url(\"../images/banner/bg-2.jpg\");\n  -webkit-background-size: cover;\n  background-size: cover;\n  position: relative;\n}\n\n.banner-2 {\n  background: url(\"../images/banner/slider-3.jpg\");\n  -webkit-background-size: cover;\n  background-size: cover;\n  position: relative;\n}\n\n.banner-3 {\n  position: relative;\n  background: none;\n}\n\n.banner-3 #banner-carousel,\n.banner-3 .carousel-inner,\n.banner-3 .carousel-item,\n.banner-3 .banner-slide {\n  height: 760px;\n}\n\n.banner-3 .carousel-item {\n  transition: transform 0.6s ease-in-out;\n}\n\n.banner-3 .banner-slide {\n  position: relative;\n  -webkit-background-size: cover;\n  background-size: cover;\n  background-position: center center;\n}\n\n.banner-3 .banner-slide .d-table,\n.banner-3 .banner-slide .d-table-cell {\n  height: 100%;\n}\n\n.banner-3 .banner-slide .overlay {\n  z-index: 0;\n}\n\n.banner-3 .banner-slide .d-table {\n  position: relative;\n  z-index: 2;\n}\n\n.banner-3 .banner-carousel-indicators {\n  margin-bottom: 0;\n  bottom: 45px;\n  left: 0;\n  right: 0;\n  transform: none;\n  width: 100%;\n  margin-left: 0;\n  margin-right: 0;\n  justify-content: center;\n}\n\n.banner-3 .banner-carousel-indicators li {\n  width: 10px;\n  height: 10px;\n  margin: 0 7px;\n  border-radius: 50%;\n  border: 0;\n  background: rgba(255, 255, 255, 0.45);\n  opacity: 1;\n}\n\n.banner-3 .banner-carousel-indicators li.active {\n  width: 34px;\n  border-radius: 999px;\n  background: #fff;\n}\n\n.section-heading h2 {\n  margin-bottom: 20px;\n  font-weight: 400;\n}\n\n/* =======================================\nINner Pages\n=========================================*/\n#page-banner {\n  position: relative;\n  padding: 60px 0px 80px;\n}\n\n.page-banner-area {\n  background: url(\"../images/banner/1.jpg\") no-repeat 50% 50%;\n  background-size: cover;\n}\n\n/*-------------------- ------------\n INTRO SECTION\n-----------------------------*/\n#intro {\n  padding-bottom: 0px;\n}\n\n.intro-img {\n  margin-top: 45px;\n}\n\n#intro .section-heading p {\n  color: #0b80bb;\n  font-size: 30px;\n  line-height: 40px;\n}\n\n.intro-box {\n  margin-top: 30px;\n  position: relative;\n  margin-bottom: 20px;\n}\n\n.intro-box h4:before {\n  position: absolute;\n  left: 0px;\n  top: 17px;\n  content: \"\";\n  bottom: 0px;\n  background: #0b80bb;\n  width: 50px;\n  height: 2px;\n}\n\n.intro-box h4 {\n  text-transform: uppercase;\n  margin-bottom: 15px;\n  position: relative;\n  padding-left: 60px;\n}\n\n.intro-box span {\n  font-size: 28px;\n  color: #00a7e1;\n}\n\n.intro-cta {\n  margin-top: 40px;\n}\n\n/*--------------------------\n  ABOUT SECTION\n----------------------*/\n.section-pt {\n  padding-top: 90px;\n}\n\n.section-pb {\n  padding-bottom: 90px;\n}\n\n#about {\n  position: relative;\n  padding-bottom: 85px;\n}\n\n.about-bg-img {\n  position: absolute;\n  right: 0px;\n  content: \"\";\n  background: url(\"../images/banner/1.jpg\") 50% 50%;\n  width: 40%;\n  height: 100%;\n  max-height: 560px;\n  top: 0px;\n  -webkit-box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n  box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n}\n\n.about-content {\n  margin-top: 94px;\n}\n\n.about-content .subtitle {\n  margin-bottom: 20px;\n  text-transform: uppercase;\n}\n\n.about-content h3 {\n  margin-bottom: 25px;\n}\n\n.about-list {\n  margin-top: 30px;\n}\n\n.about-list li {\n  width: 45%;\n  float: left;\n  margin-bottom: 15px;\n  margin-right: 15px;\n  color: #888;\n}\n\n.about-list li i {\n  color: #0b80bb;\n  margin-right: 10px;\n}\n\n/* ----------------------\nABOUT PAGE\n-------------------------*/\n.about-list2 li i {\n  margin-right: 10px;\n  color: #00a7e1;\n}\n\n.icon-3x {\n  font-size: 3rem;\n}\n\n.text-default {\n  color: #00a7e1;\n}\n\n.team-social li a {\n  font-size: 13px;\n  width: 30px;\n  height: 30px;\n  text-align: center;\n  border: 1px solid #fff;\n  display: inline-block;\n  padding-top: 3px;\n  background: #fff;\n}\n\n/* ========================\nHISTORY MISSION\n==============================*/\n.img-block img {\n  width: 200px;\n}\n\n/* ========================\n\n==============================*/\n#section-strategy {\n  background: url(\"../images/bg/bg-1.jpg\") 50% 50% no-repeat;\n  background-size: cover;\n}\n\n.strategy-text {\n  margin-bottom: 50px;\n}\n\n.strategy-text h4 {\n  font-size: 18px;\n  margin-bottom: 10px;\n  font-weight: 600;\n}\n\n.strategy-text span {\n  font-size: 61px;\n  color: #00a7e1;\n  margin-bottom: 15px;\n  display: block;\n}\n\n/*--------------------------------\n COUNTER SECTION\n-----------------------------*/\n.counter {\n  font-size: 60px;\n  line-height: 60px;\n  font-weight: 700;\n  line-height: 70px;\n  margin: 10px 0px;\n  color: #00a7e1;\n}\n\n.counter-stat i {\n  font-size: 40px;\n  color: #fff;\n  margin-right: 10px;\n}\n\n.counter-stat h5 {\n  font-weight: 400;\n  text-transform: uppercase;\n  color: #fff;\n}\n\n.counter-block span {\n  font-size: 30px;\n}\n\n#counter .dark-overlay {\n  background: #0b80bb;\n  opacity: 0.95;\n}\n\n#counter {\n  background: url(\"../images/banner/pattern-3.png\") fixed 50% 50%;\n  position: relative;\n  -webkit-background-size: cover;\n  background-size: cover;\n  padding-top: 87px;\n  padding-bottom: 95px;\n}\n\n/*--------------------------\n  SERVICE AREA SECTION\n----------------------*/\n.page-banner-area.page-service {\n  background: url(\"../images/bg/bg-2.jpg\") no-repeat;\n  background-size: cover;\n}\n\n#service-head {\n  padding-bottom: 100px;\n  padding-top: 90px;\n}\n\n#service-head .section-title {\n  color: #fff;\n}\n\n.text-white p {\n  color: #fff;\n}\n\n#service {\n  margin-top: -100px;\n  padding-bottom: 70px;\n}\n\n.service-box .service-img-icon {\n  width: 100px;\n  height: 100px;\n  text-align: center;\n  background: #fff;\n  padding-top: 20px;\n  margin: 0 auto;\n  border-radius: 100%;\n  margin-bottom: 20px;\n  background: #00a7e1;\n  border: 1px solid rgba(255, 255, 255, 0.2);\n  color: #fff;\n}\n\n.service-box {\n  margin-bottom: 40px;\n  background: #fff;\n  text-align: center;\n  padding: 45px 25px 30px 25px;\n  border: 1px solid transparent;\n  -webkit-transition: all 0.3s ease 0s;\n  -o-transition: all 0.3s ease 0s;\n  transition: all 0.3s ease 0s;\n  border-radius: 5px;\n  -webkit-box-shadow: 0px 2px 6px rgba(0, 0, 0, 0.1);\n  box-shadow: 0px 2px 6px rgba(0, 0, 0, 0.1);\n}\n\n.service-inner {\n  margin-top: 30px;\n}\n\n.service-inner h4 {\n  margin-bottom: 20px;\n}\n\n.service-inner span {\n  color: #00a7e1;\n}\n\n/* ================================\nSERVICE PAGE\n==============================*/\n.bg-gray {\n  background: #f4f4f4;\n}\n\n.service-block-2 {\n  position: relative;\n}\n\n.service-block-2 h4 {\n  margin-bottom: 15px;\n  line-height: 26px;\n}\n\n.service-block-2 p {\n  font-size: 16px;\n}\n\n.service-block-2 span {\n  position: absolute;\n  content: \"\";\n  font-size: 70px;\n  top: 0px;\n  left: 0px;\n  font-weight: 800;\n  opacity: 0.05;\n  margin-top: -15px;\n}\n\n.service-style-two {\n  background: url(\"../images/bg/bg-2.jpg\") no-repeat;\n  background-size: cover;\n  position: relative;\n}\n\n.service-style-two:before {\n  position: absolute;\n  content: \"\";\n  left: 0px;\n  top: 0px;\n  height: 100%;\n  width: 100%;\n  background: rgba(0, 0, 0, 0.6);\n}\n\n.heading {\n  margin-bottom: 70px;\n}\n\n/*------------------------------------\n  PRICING SECTION AREA\n--------------------------------*/\n#pricing {\n  padding-bottom: 100px;\n}\n\n.pricing-block {\n  text-align: center;\n  -webkit-transition: all 0.3s 0s ease;\n  -o-transition: all 0.3s 0s ease;\n  transition: all 0.3s 0s ease;\n  border-radius: 5px;\n  border: 1px solid #eee;\n}\n\n.price-header {\n  padding-bottom: 30px;\n  padding-top: 30px;\n}\n\n.price-header i {\n  width: 100px;\n  height: 100px;\n  text-align: center;\n  padding-top: 25px;\n  font-size: 50px;\n  display: inline-block;\n  border-radius: 100%;\n  -webkit-transition: all 0.3s ease 0s;\n  -o-transition: all 0.3s ease 0s;\n  transition: all 0.3s ease 0s;\n  color: #00a7e1;\n  border: 1px solid #eee;\n}\n\n.price-header .price {\n  font-size: 70px;\n  margin-top: 40px;\n  margin-bottom: 0px;\n}\n\n.price-header h5 {\n  font-weight: 400;\n}\n\n.price-header .price small {\n  font-size: 18px;\n}\n\n.pricing-block ul {\n  padding: 20px 20px;\n  margin-bottom: 30px;\n  border-bottom: 1px solid #eee;\n}\n\n.pricing-block ul li {\n  padding: 6px 0px;\n}\n\n.pricing-block .btn {\n  margin-bottom: 30px;\n}\n\n.pricing-block:hover i {\n  background-image: -webkit-linear-gradient(135deg, #2f1ce0 0%, #53a0fd 50%, #51eca5 100%);\n  background-iamge: -linear-gradient(135deg, #2f1ce0 0%, #53a0fd 50%, #51eca5 100%);\n  color: #fff;\n  border: 1px solid #53a0fd;\n}\n\n.pricing-block:hover,\n.pricing-block.active {\n  background: #fff;\n  -webkit-box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n  box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n}\n\n#pricing .section-heading {\n  margin-bottom: 90px;\n}\n\n/* -------------------\nPRICING PAGE\n--------------------*/\n#section-counter .counter-stat i {\n  color: #0b80bb;\n}\n\n#section-counter .counter-stat h5 {\n  color: #777;\n}\n\n/*------------------------------------\n  CLIENT PARTNER AREA SECTION\n--------------------------------*/\n#clients {\n  padding-top: 75px;\n  padding-bottom: 80px;\n  position: relative;\n}\n\n.client-img {\n  background: #fff;\n}\n\n/*------------------------------------\n  TESTIMONIAL AREA SECTION\n---------------------------------*/\n.author-img img {\n  width: 100px;\n  height: 100px;\n  border-radius: 100%;\n  border: 5px solid #ddd;\n}\n\n.author-info p {\n  margin: 0px;\n  font-size: 14px;\n}\n\n.carousel-indicators {\n  bottom: 0px;\n  margin-bottom: 0px;\n}\n\n.carousel-indicators li {\n  background: #111;\n  width: 10px;\n  height: 10px;\n  border-radius: 100%;\n}\n\n.carousel-indicators li.active {\n  background: #00a7e1;\n}\n\n.testimonial-content {\n  padding: 0px 40px;\n  text-align: center;\n  margin-bottom: 40px;\n}\n\n.testimonial-content .author-text {\n  padding-top: 10px;\n}\n\n.testimonial-content .author-info {\n  display: block;\n  margin-bottom: 25px;\n}\n\n.testimonial-content p {\n  font-size: 20px;\n  line-height: 36px;\n  color: #222;\n  margin: 35px 0px;\n  display: block;\n}\n\n.author-text h5 {\n  text-transform: uppercase;\n}\n\n.author-text p {\n  font-size: 14px;\n  line-height: 20px;\n  margin-bottom: 36px;\n  color: #888;\n  margin: 0px;\n}\n\n.testimonial-content p i {\n  margin: 0px 8px;\n}\n\n.carousel-indicators li {\n  border-top: 0 !important;\n  border-bottom: 0 !important;\n}\n\n/*--------------------------\n CONTACT SECTION AREA\n----------------------*/\n#contact {\n  padding-bottom: 100px;\n}\n\n.text-color {\n  color: #00a7e1;\n}\n\ninput[type=text],\ninput[type=email] {\n  height: 50px;\n}\n\n.form-control {\n  border: 1px solid #eee;\n  padding-left: 20px;\n}\n\n.form-control:hover,\n.form-control:focus {\n  -webkit-box-shadow: 0px 5px 35px 0px rgba(148, 146, 245, 0.15);\n  box-shadow: 0px 5px 35px 0px rgba(148, 146, 245, 0.15);\n}\n\n.input:focus {\n  outline: none;\n}\n\n.form-control::-webkit-input-placeholder {\n  color: #888;\n  opacity: 0.9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control::-moz-placeholder {\n  color: #888;\n  opacity: 0.9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control:-ms-input-placeholder {\n  color: #888;\n  opacity: 0.9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control:-moz-placeholder {\n  color: #888;\n  opacity: 0.9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n/* --------------\n    MAP\n-----------------*/\n#map {\n  height: 400px;\n  width: 100%;\n  position: relative;\n}\n\n/*--------------------------\n BLOG SECTION AREA\n----------------------*/\n#blog {\n  padding-bottom: 55px;\n}\n\n.blog-block {\n  overflow: hidden;\n  -webkit-transition: all 0.3s ease 0s;\n  -o-transition: all 0.3s ease 0s;\n  transition: all 0.3s ease 0s;\n}\n\n.blog-block img {\n  margin-bottom: 10px;\n}\n\n.blog-text {\n  padding: 20px;\n}\n\n.blog-text .author-name {\n  font-weight: 400;\n}\n\n.blog-text .author-name span {\n  margin-right: 10px;\n  font-weight: 600;\n}\n\n.blog-block .read-more,\n.blog-block span {\n  color: #00a7e1;\n}\n\n/* =================================\nBLOG PAGE\n===================================*/\n.blog-post {\n  margin-bottom: 50px;\n}\n\n.blog-post img {\n  border-radius: 5px;\n}\n\n.blog-post .post-author i,\n.blog-post .post-info i {\n  margin-right: 5px;\n  font-size: 14px;\n}\n\n.blog-post .post-author span,\n.blog-post .post-info span {\n  font-size: 14px;\n}\n\n.sidebar-widget {\n  margin-bottom: 40px;\n  padding-left: 20px;\n}\n@media (max-width: 992px) {\n  .sidebar-widget {\n    padding-left: 0;\n  }\n}\n\n.category ul li {\n  margin-bottom: 10px;\n  text-transform: capitalize;\n  position: relative;\n  padding-left: 20px;\n  border-bottom: 1px solid #eee;\n  padding-bottom: 10px;\n}\n\n.category ul li:before {\n  position: absolute;\n  content: \"\\f105\";\n  left: 0px;\n  top: 0px;\n  font-family: \"Font Awesome 5 Free\";\n  color: #00a7e1;\n  font-weight: 900;\n}\n\n.tag a {\n  text-transform: capitalize;\n  padding: 5px 8px;\n  border: 1px solid #eee;\n  margin-bottom: 5px;\n  font-size: 14px;\n  display: inline-block;\n}\n\n.search i {\n  position: absolute;\n  right: 0px;\n  top: 0px;\n  margin-right: 35px;\n  margin-top: 15px;\n  color: #00a7e1;\n}\n\n.download a {\n  display: block;\n  padding: 12px 20px;\n  border: 1px solid #eee;\n  margin-bottom: 10px;\n  background: #f2f2f2;\n}\n\n.download a i {\