ht: 36px;\n  }\n  /*--------------------\n     BANNER\n    -----------------*/\n  .banner-content .banner-title {\n    line-height: 37px;\n  }\n  .banner-content p {\n    font-size: 16px;\n  }\n  /*----------------\n     INTRO\n    ----------------*/\n  #intro {\n    padding-bottom: 90px;\n  }\n  /*----------------\n     ABOUT\n    ----------------*/\n  .about-list li {\n    float: none;\n    width: 100%;\n    margin-bottom: 10px;\n  }\n  .about-bg-img {\n    width: 35%;\n    height: 100%;\n    max-height: 600px;\n  }\n  .about-content {\n    margin-top: 60px;\n  }\n  #about {\n    padding-bottom: 40px;\n  }\n  .img-block img {\n    width: 130px;\n  }\n  .service-block {\n    margin-bottom: 20px;\n  }\n  /*-------------------\n     TESTIMONIAL\n    -------------------*/\n  .testimonial-content {\n    padding: 10px;\n  }\n  /*--------------\n     COUNTER\n    ----------------*/\n  .counter-stat {\n    margin-bottom: 30px;\n    text-align: center;\n  }\n  /*--------------\n     BLOG\n    ----------------*/\n  .blog-block {\n    margin-bottom: 30px;\n  }\n  .blog-text {\n    padding: 10px;\n    margin-top: 10px;\n    text-align: center;\n  }\n  .blog-tex h5 {\n    font-size: 15px;\n  }\n  .blog-text p {\n    font-size: 14px;\n  }\n  /*--------------\n     CLIENT\n    --------------*/\n  .client-img {\n    text-align: center;\n  }\n  /*--------------\n     FOOTER\n    ----------------*/\n  .footer-widget {\n    margin-bottom: 30px;\n  }\n  .pricing-block {\n    margin-bottom: 30px;\n  }\n}",".no-padding {\n  padding: 0;\n}\n\n.flaticon {\n  display: inline;\n}\n\n.mb30 {\n  margin-bottom: 30px;\n}\n\n.section-padding {\n  padding: 90px 0px;\n}\n\n.section-heading {\n  text-align: center;\n  width: 70%;\n  margin: 0 auto 60px;\n}\n\n.section-title {\n  font-size: 32px;\n  line-height: 38px;\n  margin-bottom: 15px;\n  text-transform: capitalize\n}\n\n.section-title span {\n  color: #00a7e1;\n}\n\n.section {\n  padding: 100px 0px;\n}\n\n\n.line {\n  width: 50px;\n  background: #00a7e1;\n  height: 1px;\n  margin: 10px auto;\n}\n\n\n\n\n/*---------- BUTTONS ----------*/\n\n.btn {\n  font: 600 10.5px/1;\n  display: inline-block;\n  padding: 15px 45px 15px 45px;\n  text-transform: uppercase;\n  border: 2px solid transparent;\n  -webkit-transition: all .2s;\n  transition: all .2s;\n  border-radius: 0px;\n  font-weight: 600;\n  font-size: 13px;\n  letter-spacing: 1px;\n}\n\n.btn:focus,\n.btn:active,\n.btn:active:focus {\n  outline: none;\n  box-shadow: none;\n}\n\n.btn-hero,\n.btn-white:hover {\n  color: #fff !important;\n  background: #00a7e1;\n}\n\n.btn-hero:focus {\n  color: #fff !important;\n}\n\n.btn-black,\n.btn-hero:hover {\n  background-color: rgba(0, 0, 0, 1);\n  color: #fff !important;\n}\n\n.btn-black:hover {\n  color: #fff;\n  background: #00a7e1;\n}\n\n.btn-black:focus {\n  color: #fff;\n}\n\n.btn-white {\n  background-color: rgba(255, 255, 255, .95);\n  color: rgba(0, 0, 0, .85);\n  border-color: rgba(255, 255, 255, .12);\n}\n\n.btn-white:focus {\n  color: #0b80bb;\n}\n\n.btn-white:active {\n  color: #fff;\n}\n\n.btn-trans-black {\n  background-color: transparent;\n  border: 2px solid rgba(0, 0, 0, .15);\n  color: rgba(0, 0, 0, .85);\n}\n\n.btn-trans-black:hover {\n  color: rgba(255, 255, 255, 1);\n  background-color: #0b80bb;\n}\n\n.btn-trans-white {\n  background-color: transparent;\n  border: 2px solid rgba(255, 255, 255, .15);\n  color: rgba(255, 255, 255, .95);\n}\n\n.btn-trans-white:hover {\n  background-color: rgba(255, 255, 255, .95);\n  color: rgba(0, 0, 0, .85);\n  border-color: rgba(255, 255, 255, .12);\n}\n\n.btn-trans-white:active,\n.btn-trans-white:focus {\n  color: #fff;\n  background-color: transparent;\n  border-color: rgba(255, 255, 255, .12);\n}\n\n.btn-rounded {\n  border-radius: 2px;\n}\n\n.btn-circled {\n  border-radius: 40px;\n}\n\n\n.btn-trans-black:hover {\n  background: #00a7e1 !important;\n}\n\n\n\n/*---------- COLORS ----------*/\n\n/*-- Background Colors --*/\n\n.bg-black {\n  background-color: #0b80bb;\n}\n\n.bg-dark {\n  background-color: rgba(0, 0, 0, .96);\n}\n\n.bg-feature {\n  background-color: #00a7e1;\n}\n\n.bg-primary {\n  background-color: #0db8ca;\n}\n\n.bg-gray {\n  background-color: #f2f4ec;\n}\n\n.bg-white {\n  background-color: #fff;\n}\n\n\n.d-table {\n  width: 100%;\n}\n\n\n.d-table-cell {\n  vertical-align: middle;\n}\n\n\n.overlay {\n  position: absolute;\n  top: 0px;\n  left: 0px;\n  width: 100%;\n  height: 100%;\n  background: rgba(0, 0, 0, 0.5);\n}\n\n.brown-overlay {\n  background: #222955;\n  opacity: .97;\n}\n\n.feature-overlay {\n  background: #00a7e1;\n  opacity: .97;\n}\n\n.gr-overlay {\n  background: linear-gradient(135deg, #2f1ce0 0%, #53a0fd 30%, #51eca5 100%);\n  opacity: .87;\n}\n\n\n/* ========================\n\n==============================*/\n\n.heading {\n  margin-bottom: 40px;\n}\n\n.heading h3 {\n  margin-bottom: 10px;\n  font-weight: 600;\n}\n","/*------------------------------------\n  MENU NAVIGATION AREA\n----------------------------------*/\n.site-navigation,\n.trans-navigation {\n  padding: 20px 0px;\n}\n\n.site-navigation .navbar-nav a,\n.trans-navigation .navbar-nav a {\n  text-transform: uppercase;\n}\n\n.site-navigation .navbar-nav a.active,\n.trans-navigation .navbar-nav a.active {\n  color: red;\n}\n\n.header-white {\n  position: fixed;\n  top: 0px;\n  background: #111;\n  z-index: 9999;\n  width: 100%;\n  left: 0;\n  -webkit-transition: all .3s ease 0s;\n  -o-transition: all .5s ease 0s;\n  transition: all .5s ease 0s;\n  color: $black !important;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link,\n.navbar-expand-lg.site-navigation .navbar-nav .nav-link {\n  padding: 0px 24px;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link:last-child,\n.navbar-expand-lg.site-navigation .navbar-nav .nav-link:last-child {\n  padding-right: 0px;\n}\n\n.site-navigation,\n.trans-navigation {\n  -webkit-transition: all .3s ease 0s;\n  -o-transition: all .5s ease 0s;\n  transition: all .5s ease 0s;\n}\n\n.navbar-brand {\n  padding-top: 0px;\n  margin-right: 60px;\n  font-weight: 700;\n  text-transform: capitalize;\n  color: $light;\n}\n\n.navbar-brand span {\n  font-weight: 400;\n}\n\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link {\n  color: $light;\n}\n\n.trans-navigation {\n  background: transparent;\n}\n\n.trans-navigation.header-white {\n  background: #111;\n}\n\n.trans-navigation.header-white .navbar-nav .nav-link {\n  color: $light;\n}\n\n.trans-navigation.header-white .navbar-nav a.active {\n  color: $primary-color;\n\n}\n\n.navbar-brand img {\n  max-width: 100%;\n}\n\n.trans-navigation.header-white .btn-white {\n  background: $primary-color;\n  color: $light;\n}\n\n/* ===============================\n DROPDOWN MENU\n================================*/\n.navbar-expand-lg.trans-navigation .navbar-nav .nav-link.dropdown-toggle {\n  padding-right: 0px;\n}\n\n.dropdown-toggle i {\n  font-size: 10px;\n  vertical-align: 2px;\n}\n\n.dropdown-menu {\n  padding: 0px;\n  border: 0;\n  box-shadow: 2px 2px 5px 1px rgba(0, 0, 0, 0.05), -2px 0px 5px 1px rgba(0, 0, 0, 0.05);\n\n  @include desktop {\n    text-align: center;\n    float: left !important;\n    width: 100%;\n    margin: 0;\n  }\n\n  li:first-child {\n    margin-top: 5px\n  }\n\n  li:last-child {\n    margin-bottom: 5px\n  }\n}\n\n.dropdown-toggle::after {\n  display: none;\n}\n\n.dropleft .dropdown-menu,\n.dropright .dropdown-menu {\n  margin: 0;\n}\n\n.dropleft .dropdown-toggle::before,\n.dropright .dropdown-toggle::after {\n  font-weight: bold;\n  font-family: 'Font Awesome 5 Free';\n  border: 0;\n  font-size: 10px;\n  vertical-align: 1px;\n}\n\n.dropleft .dropdown-toggle::before {\n  content: \"\\f053\";\n  margin-right: 5px;\n}\n\n.dropright .dropdown-toggle::after {\n  content: \"\\f054\";\n  margin-left: 5px;\n}\n\n.dropdown-item {\n  padding: .6rem 1.5rem .35rem;\n  text-transform: uppercase;\n  font-size: 14px;\n  font-weight: 500;\n}\n\n.dropdown-submenu.active>.dropdown-toggle,\n.dropdown-submenu:hover>.dropdown-item,\n.dropdown-item.active,\n.dropdown-item:hover {\n  background: rgba($primary-color, .1);\n  color: $primary-color;\n}\nbutton:focus {\n  outline: 0;\n}\n\nul.dropdown-menu li {\n  padding-left: 0px !important;\n}\n\n@media (min-width:992px) {\n  .dropdown-menu {\n    transition: all .2s ease-in, visibility 0s linear .2s, transform .2s linear;\n    display: block;\n    visibility: hidden;\n    opacity: 0;\n    min-width: 200px;\n    transform: translateY(10px);\n\n    li:first-child {\n      margin-top: 5px\n    }\n\n    li:last-child {\n      margin-bottom: 5px\n    }\n  }\n\n  .dropleft .dropdown-menu,\n  .dropright .dropdown-menu {\n    margin-top: -5px;\n  }\n\n  .dropdown:hover>.dropdown-menu {\n    visibility: visible;\n    transition: all .3s ease 0s;\n    opacity: 1;\n    transform: translateY(0);\n  }\n}\n\n.navbar-collapse {\n  @include desktop {\n    text-align: center;\n  }\n\n  &.show {\n    overflow-y: auto;\n    max-height: calc(100vh - 100px);\n  }\n}","\n\n/*------------------------------------\n BANNER AREA\n----------------------------------*/\n\n.banner-area .content-padding {\n    padding: 250px 0px 180px;\n}\n\n\n.content-padding {\n    padding: 180px 0px 80px;\n}\n\n.banner-content {\n    padding-right: 30px;\n}\n\n.banner-content .btn {\n    margin-top: 15px;\n}\n\n\n.banner-content .banner-title {\n    color: $light;\n    font-weight: 700;\n    line-height: 50px;\n}\n\n.banner-content .subtitle {\n    color: $light;\n    background:$primary-color;\n    display: inline-block;\n    padding: 3px 8px;\n    margin-bottom: 20px;\n    text-transform: uppercase;\n}\n\n.subtitle {\n    color:$primary-color;\n}\n\n.banner-content p {\n    margin: 20px 0px;\n    color: $border-color;\n    font-size: 18px;\n    line-height: 30px;\n}\n\n\n\n.banner-content .btn {\n    margin-right: 12px;\n}\n\n.btn-sm {\n    padding: 10px 30px;\n}\n\n\n.banner-1 {\n    background: url(\"../images/banner/bg-2.jpg\");\n    -webkit-background-size: cover;\n    background-size: cover;\n    position: relative;\n}\n\n.banner-2 {\n    background: url(\"../images/banner/slider-3.jpg\");\n    -webkit-background-size: cover;\n    background-size: cover;\n    position: relative;\n}\n\n.banner-3 {\n    position: relative;\n    background: none;\n}\n\n.banner-3 #banner-carousel,\n.banner-3 .carousel-inner,\n.banner-3 .carousel-item,\n.banner-3 .banner-slide {\n    height: 760px;\n}\n\n.banner-3 .carousel-item {\n    transition: transform .6s ease-in-out;\n}\n\n.banner-3 .banner-slide {\n    position: relative;\n    -webkit-background-size: cover;\n    background-size: cover;\n    background-position: center center;\n}\n\n.banner-3 .banner-slide .d-table,\n.banner-3 .banner-slide .d-table-cell {\n    height: 100%;\n}\n\n.banner-3 .banner-slide .overlay {\n    z-index: 0;\n}\n\n.banner-3 .banner-slide .d-table {\n    position: relative;\n    z-index: 2;\n}\n\n.banner-3 .banner-carousel-indicators {\n    margin-bottom: 0;\n    bottom: 45px;\n    left: 0;\n    right: 0;\n    transform: none;\n    width: 100%;\n    margin-left: 0;\n    margin-right: 0;\n    justify-content: center;\n}\n\n.banner-3 .banner-carousel-indicators li {\n    width: 10px;\n    height: 10px;\n    margin: 0 7px;\n    border-radius: 50%;\n    border: 0;\n    background: rgba(255, 255, 255, 0.45);\n    opacity: 1;\n}\n\n.banner-3 .banner-carousel-indicators li.active {\n    width: 34px;\n    border-radius: 999px;\n    background: #fff;\n}\n\n\n.section-heading h2 {\n    margin-bottom: 20px;\n    font-weight: 400;\n}\n","\n/* =======================================\nINner Pages\n=========================================*/\n\n#page-banner{\n    position: relative;\n    padding: 60px 0px 80px;\n}\n.page-banner-area{\n    background:url(\"../images/banner/1.jpg\")no-repeat 50% 50%;\n    background-size: cover;\n}\n\n","\n/*-------------------- ------------\n INTRO SECTION\n-----------------------------*/\n\n#intro {\n    padding-bottom: 0px;\n}\n\n.intro-img {\n    margin-top: 45px;\n}\n\n#intro .section-heading p {\n    color:$black;\n    font-size: 30px;\n    line-height: 40px;\n}\n\n.intro-box {\n    margin-top: 30px;\n    position: relative;\n    margin-bottom: 20px;\n}\n\n.intro-box h4:before {\n    position: absolute;\n    left: 0px;\n    top: 17px;\n    content: \"\";\n    bottom: 0px;\n    background:$black;\n    width: 50px;\n    height: 2px;\n}\n\n.intro-box h4 {\n    text-transform: uppercase;\n    margin-bottom: 15px;\n    position: relative;\n    padding-left: 60px;\n}\n\n.intro-box span {\n    font-size: 28px;\n    color: $primary-color;\n}\n\n\n.intro-cta{\n    margin-top: 40px;\n}\n\n\n\n","\n\n/*--------------------------\n  ABOUT SECTION\n----------------------*/\n\n.section-pt {\n    padding-top: 90px;\n}\n\n.section-pb {\n    padding-bottom: 90px;\n}\n\n#about {\n    position: relative;\n    padding-bottom: 85px;\n}\n\n.about-bg-img {\n    position: absolute;\n    right: 0px;\n    content: \"\";\n    background: url(\"../images/banner/1.jpg\") 50% 50%;\n    width: 40%;\n    height: 100%;\n    max-height: 560px;\n    top: 0px;\n    -webkit-box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n    box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n}\n\n\n.about-content {\n    margin-top:94px;\n}\n\n.about-content .subtitle {\n    margin-bottom: 20px;\n    text-transform: uppercase;\n}\n\n.about-content h3 {\n    margin-bottom: 25px;\n}\n\n.about-list {\n    margin-top: 30px;\n}\n\n.about-list li {\n    width: 45%;\n    float: left;\n    margin-bottom: 15px;\n    margin-right: 15px;\n    color: #888;\n}\n\n.about-list li i {\n    color: $black;\n    margin-right: 10px;\n}\n\n\n/* ----------------------\nABOUT PAGE\n-------------------------*/\n\n\n.about-list2 li i{\n    margin-right: 10px;\n    color: $primary-color;\n}\n\n.icon-3x{\n    font-size: 3rem;\n}\n.text-default{\n    color: $primary-color;\n}\n\n\n\n.team-social li a{\n    font-size: 13px;\n    width: 30px;\n    height: 30px;\n    text-align: center;\n    border: 1px solid $light;\n    display: inline-block;\n    padding-top: 3px;\n    background: $light;\n}\n\n\n/* ========================\nHISTORY MISSION\n==============================*/\n\n.img-block img{\n    width: 200px;\n}\n\n\n/* ========================\n\n==============================*/\n#section-strategy{\n    background: url(\"../images/bg/bg-1.jpg\") 50% 50% no-repeat;\n    background-size: cover;\n}\n.strategy-text{\n    margin-bottom: 50px;\n}\n\n.strategy-text h4{\n    font-size: 18px;\n    margin-bottom: 10px;\n    font-weight: 600;\n}\n\n.strategy-text span{\n    font-size: 61px;\n    color: $primary-color;\n    margin-bottom: 15px;\n    display: block;\n}","\n/*--------------------------------\n COUNTER SECTION\n-----------------------------*/\n\n.counter {\n    font-size: 60px;\n    line-height: 60px;\n    font-weight: 700;\n    line-height: 70px;\n    margin: 10px 0px;\n    color: $primary-color;\n}\n\n.counter-stat i {\n    font-size: 40px;\n    color: $light;\n    margin-right: 10px;\n}\n\n.counter-stat h5 {\n    font-weight: 400;\n    text-transform: uppercase;\n    color: $light;\n}\n\n.counter-block span {\n    font-size: 30px;\n}\n\n\n#counter .dark-overlay {\n    background:$black;\n    opacity: 0.95;\n}\n\n#counter {\n    background: url(\"../images/banner/pattern-3.png\") fixed 50% 50%;\n    position: relative;\n    -webkit-background-size: cover;\n    background-size: cover;\n    padding-top: 87px;\n    padding-bottom: 95px;\n}\n\n","\n/*--------------------------\n  SERVICE AREA SECTION\n----------------------*/\n.page-banner-area.page-service{\n    background: url(\"../images/bg/bg-2.jpg\") no-repeat;\n    background-size: cover;\n}\n#service-head {\n    padding-bottom: 100px;\n    padding-top: 90px;\n}\n#service-head .section-title{\n    color: $light;\n}\n.text-white p {\n    color: $light;\n}\n\n#service {\n    margin-top: -100px;\n    padding-bottom:70px;\n}\n\n.service-box .service-img-icon {\n    width: 100px;\n    height: 100px;\n    text-align: center;\n    background: $light;\n    padding-top: 20px;\n    margin: 0 auto;\n    border-radius: 100%;\n    margin-bottom: 20px;\n    background:$primary-color;\n    border: 1px solid rgba(255,255,255,.2);\n    color: $light;\n}\n\n.service-box {\n    margin-bottom: 40px;\n    background: $light;\n    text-align: center;\n    padding: 45px 25px 30px 25px;\n    border: 1px solid transparent;\n    -webkit-transition: all .3s ease 0s;\n    -o-transition: all .3s ease 0s;\n    transition: all .3s ease 0s;\n    border-radius: 5px;\n    -webkit-box-shadow: 0px 2px 6px rgba(0,0,0,0.1);\n    box-shadow: 0px 2px 6px rgba(0,0,0,0.1);\n}\n\n\n.service-inner {\n    margin-top: 30px;\n}\n\n.service-inner h4 {\n    margin-bottom: 20px;\n}\n\n.service-inner span {\n    color:$primary-color;\n}\n\n\n/* ================================\nSERVICE PAGE\n==============================*/\n\n.bg-gray{\n    background: $secondary-color;\n}\n\n.service-block-2{\n    position: relative;\n}\n.service-block-2 h4{\n    margin-bottom: 15px;\n    line-height: 26px;\n}\n\n.service-block-2 p{\n    font-size: 16px;\n}\n\n.service-block-2 span{\n    position: absolute;\n    content: \"\";\n    font-size: 70px;\n    top: 0px;\n    left: 0px;\n    font-weight: 800;\n    opacity: .05;\n    margin-top: -15px;\n}\n\n.service-style-two{\n    background: url(\"../images/bg/bg-2.jpg\") no-repeat;\n    background-size: cover;\n    position: relative;\n}\n\n.service-style-two:before{\n    position: absolute;\n    content:\"\";\n    left: 0px;\n    top: 0px;\n    height: 100%;\n    width: 100%;\n    background:rgba(0,0,0,0.6);\n}\n\n\n.heading{\n    margin-bottom: 70px;\n}","\n/*------------------------------------\n  PRICING SECTION AREA\n--------------------------------*/\n#pricing{\n    padding-bottom: 100px;\n}\n.pricing-block {\n    text-align: center;\n    -webkit-transition: all .3s 0s ease;\n    -o-transition: all .3s 0s ease;\n    transition: all .3s 0s ease;\n    border-radius: 5px;\n    border: 1px solid $border-color;\n}\n\n.price-header {\n    padding-bottom: 30px;\n    padding-top: 30px;\n}\n\n.price-header i {\n    width: 100px;\n    height: 100px;\n    text-align: center;\n    padding-top: 25px;\n    font-size: 50px;\n    display: inline-block;\n    border-radius: 100%;\n    -webkit-transition: all .3s ease 0s;\n    -o-transition:all .3s ease 0s ;\n    transition: all .3s ease 0s;\n    color: $primary-color;\n    border: 1px solid $border-color;\n}\n\n.price-header .price {\n    font-size: 70px;\n    margin-top: 40px;\n    margin-bottom: 0px;\n}\n\n.price-header h5 {\n    font-weight: 400;\n}\n\n.price-header .price small {\n    font-size: 18px;\n}\n\n.pricing-block ul {\n    padding: 20px 20px;\n    margin-bottom: 30px;\n    border-bottom: 1px solid $border-color;\n}\n\n.pricing-block ul li {\n    padding: 6px 0px;\n}\n\n.pricing-block .btn {\n    margin-bottom: 30px;\n}\n\n\n.pricing-block:hover i {\n    background-image: -webkit-linear-gradient(135deg, #2f1ce0 0%, #53a0fd 50%, #51eca5 100%);\n    background-iamge: -linear-gradient(135deg, #2f1ce0 0%, #53a0fd 50%, #51eca5 100%);\n    color:$light;\n    border: 1px solid #53a0fd;\n\n}\n.pricing-block:hover,\n.pricing-block.active {\n    background: $light;\n    -webkit-box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n    box-shadow: 0 2px 48px 0 rgba(0, 0, 0, 0.06);\n}\n\n#pricing .section-heading {\n    margin-bottom: 90px;\n}\n\n\n\n\n/* -------------------\nPRICING PAGE\n--------------------*/\n\n#section-counter .counter-stat i{\n    color: #0b80bb;\n}\n\n#section-counter .counter-stat h5{\n    color: #777;\n}\n","/*------------------------------------\n  CLIENT PARTNER AREA SECTION\n--------------------------------*/\n\n#clients {\n  padding-top: 75px;\n  padding-bottom: 80px;\n  position: relative;\n}\n\n.client-img {\n  background: $light;\n}\n\n\n/*------------------------------------\n  TESTIMONIAL AREA SECTION\n---------------------------------*/\n.author-img img {\n  width: 100px;\n  height: 100px;\n  border-radius: 100%;\n  border: 5px solid #ddd;\n}\n\n.author-info p {\n  margin: 0px;\n  font-size: 14px;\n}\n\n.carousel-indicators {\n  bottom: 0px;\n  margin-bottom: 0px;\n}\n\n\n.carousel-indicators li {\n  background: #111;\n  width: 10px;\n  height: 10px;\n  border-radius: 100%;\n}\n\n.carousel-indicators li.active {\n  background: $primary-color;\n}\n\n\n.testimonial-content {\n  padding: 0px 40px;\n  text-align: center;\n  margin-bottom: 40px;\n}\n\n.testimonial-content .author-text {\n  padding-top: 10px;\n}\n\n.testimonial-content .author-info {\n  display: block;\n  margin-bottom: 25px;\n}\n\n.testimonial-content p {\n  font-size: 20px;\n  line-height: 36px;\n  color: #222;\n  margin: 35px 0px;\n  display: block;\n}\n\n.author-text h5 {\n  text-transform: uppercase;\n}\n\n.author-text p {\n  font-size: 14px;\n  line-height: 20px;\n  margin-bottom: 36px;\n  color: $black-lighter;\n  margin: 0px;\n}\n\n.testimonial-content p i {\n  margin: 0px 8px;\n}\n\n\n.carousel-indicators li {\n  border-top: 0 !important;\n  border-bottom: 0 !important;\n}","/*--------------------------\n CONTACT SECTION AREA\n----------------------*/\n#contact {\n  padding-bottom: 100px;\n}\n\n.text-color {\n  color: $primary-color;\n}\n\ninput[type=text],\ninput[type=email] {\n  height: 50px;\n}\n\n.form-control {\n  border: 1px solid $border-color;\n  padding-left: 20px;\n}\n\n.form-control:hover,\n.form-control:focus {\n  -webkit-box-shadow: 0px 5px 35px 0px rgba(148, 146, 245, 0.15);\n  box-shadow: 0px 5px 35px 0px rgba(148, 146, 245, 0.15);\n}\n\n.input:focus {\n  outline: none;\n}\n\n\n.form-control::-webkit-input-placeholder {\n  color: $black-lighter;\n  opacity: .9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control::-moz-placeholder {\n  color: $black-lighter;\n  opacity: .9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control:-ms-input-placeholder {\n  color: $black-lighter;\n  opacity: .9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n.form-control:-moz-placeholder {\n  color: $black-lighter;\n  opacity: .9;\n  font-size: 13px;\n  padding-left: 10px;\n}\n\n\n/* --------------\n    MAP\n-----------------*/\n#map {\n  height: 400px;\n  width: 100%;\n  position: relative;\n}","/*--------------------------\n BLOG SECTION AREA\n----------------------*/\n#blog {\n  padding-bottom: 55px;\n}\n\n.blog-block {\n  overflow: hidden;\n  -webkit-transition: all .3s ease 0s;\n  -o-transition: all .3s ease 0s;\n  transition: all .3s ease 0s;\n}\n\n.blog-block img {\n  margin-bottom: 10px;\n}\n\n.blog-text {\n  padding: 20px;\n}\n\n.blog-text .author-name {\n  font-weight: 400;\n}\n\n.blog-text .author-name span {\n  margin-right: 10px;\n  font-weight: 600;\n}\n\n\n.blog-block .read-more,\n.blog-block span {\n  color: $primary-color;\n}\n\n\n\n/* =================================\nBLOG PAGE\n===================================*/\n.blog-post {\n  margin-bottom: 50px;\n}\n\n.blog-post img {\n  border-radius: 5px;\n}\n\n.blog-post .post-author i,\n.blog-post .post-info i {\n  margin-right: 5px;\n  font-size: 14px;\n}\n\n.blog-post .post-author span,\n.blog-post .post-info span {\n  font-size: 14px;\n}\n\n\n.sidebar-widget {\n  margin-bottom: 40px;\n  padding-left: 20px;\n  @include desktop {\n    padding-left: 0;\n  }\n}\n\n.category ul li {\n  margin-bottom: 10px;\n  text-transform: capitalize;\n  position: relative;\n  padding-left: 20px;\n  border-bottom: 1px solid $border-color;\n  padding-bottom: 10px;\n}\n\n.category ul li:before {\n  position: absolute;\n  content: \"\\f105\";\n  left: 0px;\n  top: 0px;\n  font-family: \"Font Awesome 5 Free\";\n  color: $primary-color;\n  font-weight: 900;\n}\n\n.tag a {\n  text-transform: capitalize;\n  padding: 5px 8px;\n  border: 1px solid $border-color;\n  margin-bottom: 5px;\n  font-size: 14px;\n  display: inline-block;\n}\n\n.search i {\n  position: absolute;\n  right: 0px;\n  top: 0px;\n  margin-right: 35px;\n  margin-top: 15px;\n  color: $primary-color;\n}\n\n.download a {\n  display: block;\n  padding: 12px 20px;\n  border: 1px solid $border-color;\n  margin-bottom: 10px;\n  background: #f2f2f2;\n}\n\n.download a i {\n  margin-right: 15px;\n  color: $primary-color;\n}\n\n/* ==================================\nBLOG SINGLE\n=====================================*/\n\n.quote i {\n  font-size: 50px;\n  margin-right: 10px;\n  position: absolute;\n  left: 0px;\n}\n\n.quote {\n  font-size: 18px;\n  line-height: 32px;\n  color: #222;\n  position: relative;\n  margin: 50px 0px;\n  padding-left: 70px;\n}\n\n.comments img {\n  width: 80px;\n  height: 80px;\n}","\n/*--------------------------\n FOOTER\n----------------------*/\n\n#footer {\n    padding-bottom: 60px;\n    position: relative;\n    background: url(\"../images/bg/2.png\") ;\n    border-top: 1px solid $border-color;\n}\n\n.footer-widget ul li {\n    padding: 5px 0px;\n}\n\n.footer-widget p {\n    margin-bottom: 5px;\n}\n\n.footer-widget h4 {\n    margin-bottom: 20px;\n}\n\n.footer-widget h4 span {\n    color: $primary-color;\n    display: block;\n    font-size: 60px;\n    line-height: 60px;\n}\n\n.footer-blog li img {\n    width: 70px;\n    height: 70px;\n    float: left;\n    margin-right: 20px;\n}\n\n.footer-blog li h5 {\n    margin-bottom: 10px;\n    font-size: 16px;\n    line-height: 22px;\n    text-transform: capitalize;\n}\n\n.footer-blog li a.read-more {\n    font-size: 13px;\n}\n\n.footer-blog li {\n    margin-bottom: 15px;\n}\n\n.footer-copy {\n    letter-spacing: 1px;\n    padding-top: 30px;\n    margin-top: 30px;\n    border-top: 1px solid $border-color;\n}\n\n.footer-text h6 {\n    margin-bottom: 10px;\n}\n\n.footer-text p span {\n    color: $black;\n}\n\n.footer-text p.mail {\n    color: $primary-color;\n}\n\n.bg-main {\n    background: #F4F8FB;\n}\n\n.footer-widget a {\n    color: #999;\n}\n","/*-------------------------------\n RESPONSIVE LAYOUT\n---------------------------------*/\n/*Extra large devices (large desktops, 1200px and up)